def _available_symbolic_tools() -> Dict[str, str]:
    available = {}
    env_names = {
        "sage": "SAGE",
        "macaulay2": "M2",
        "gap": "GAP",
        "singular": "SINGULAR",
        "pari_gp": "GP",
        "magma": "MAGMA",
        "julia_oscar": "JULIA",
        "wolfram": "WOLFRAMSCRIPT",
    }
    for name, binaries in SYMBOLIC_TOOL_BINARIES.items():
        env_value = os.environ.get(env_names[name])
        if env_value:
            available[name] = env_value
            continue
        for binary in binaries:
            path = shutil.which(binary)
            if path:
                available[name] = path
                break
    return available


def _load_program(program_path: str):
    spec = importlib.util.spec_from_file_location("candidate_program", program_path)
    if spec is None or spec.loader is None:
        raise ImportError(f"Could not load candidate program from {program_path}")
    module = importlib.util.module_from_spec(spec)
    sys.modules["candidate_program"] = module
    spec.loader.exec_module(module)
    return module


def _candidate_triple_from_program(program_path: str) -> Tuple[Any, Any, Any]:
    module = _load_program(program_path)
    for function_name in ("solve", "build_candidate", "run"):
        function = getattr(module, function_name, None)
        if callable(function):
            result = function()
            break
    else:
        raise AttributeError("Candidate program must define solve(), build_candidate(), or run().")

    if isinstance(result, dict):
        missing = [key for key in ("g", "f", "h") if key not in result]
        if missing:
            raise KeyError(f"Candidate dictionary is missing keys: {missing}")
        return result["g"], result["f"], result["h"]

    if isinstance(result, (list, tuple)) and len(result) == 3:
        return result[0], result[1], result[2]

    raise TypeError("Candidate must return a dict with keys g,f,h or a length-3 tuple.")


def _call_with_context(function: Callable, context_values: Sequence[Any]) -> Any:
    """Call a user function with as much evaluation context as it accepts."""
    try:
        signature = inspect.signature(function)
    except (TypeError, ValueError):
        signature = None

    if signature is None:
        last_error = None
        for arg_count in range(len(context_values), -1, -1):
            try:
                return function(*context_values[:arg_count])
            except TypeError as exc:
                last_error = exc
                continue
        raise TypeError(f"Could not call {function!r} with evaluator context.") from last_error

    parameters = list(signature.parameters.values())
    has_varargs = any(param.kind == inspect.Parameter.VAR_POSITIONAL for param in parameters)
    positional = [
        param
        for param in parameters
        if param.kind
        in (inspect.Parameter.POSITIONAL_ONLY, inspect.Parameter.POSITIONAL_OR_KEYWORD)
    ]
    required = [param for param in positional if param.default is inspect.Parameter.empty]

    if has_varargs:
        arg_count = len(context_values)
    else:
        arg_count = min(len(positional), len(context_values))

    if len(required) > len(context_values):
        raise TypeError(
            f"Callable requires {len(required)} positional arguments, but evaluator has "
            f"only {len(context_values)} context values."
        )

    return function(*context_values[:arg_count])


def _identity() -> np.ndarray:
    return np.eye(MATRIX_SIZE, dtype=float)


def _as_matrix(value: Any, label: str) -> np.ndarray:
    matrix = np.asarray(value, dtype=float)
    if matrix.shape != (MATRIX_SIZE, MATRIX_SIZE):
        raise ValueError(f"{label} must evaluate to a {MATRIX_SIZE}x{MATRIX_SIZE} matrix.")
    if not np.all(np.isfinite(matrix)):
        raise ValueError(f"{label} evaluated to a non-finite matrix.")
    return matrix


def _is_scalar_like(value: Any) -> bool:
    return isinstance(value, (int, float, np.number))


def _eval_scalar(spec: Any, context: Dict[str, Any]) -> float:
    x_matrix = context["x_matrix"]
    y_matrix = context["y_matrix"]
    base_value = context.get("base_value")
    current_value = context.get("current_value")

    if _is_scalar_like(spec):
        return float(spec)

    if callable(spec):
        value = _call_with_context(spec, (x_matrix, y_matrix, base_value, current_value))
        return _eval_scalar(value, context)

    if isinstance(spec, str):
        text = spec.strip()
        try:
            return float(text)
        except ValueError:
            pass
        lowered = text.lower()
        if lowered.startswith("tr(") and lowered.endswith(")"):
            return float(np.trace(_eval_element(text[3:-1], context)))
        if lowered.startswith("trace(") and lowered.endswith(")"):
            return float(np.trace(_eval_element(text[6:-1], context)))
        if text and all(letter in {"X", "Y"} for letter in text.upper()):
            return float(np.trace(_eval_word(text, x_matrix, y_matrix)))
        raise ValueError(f"Unsupported scalar string: {spec!r}")

    if isinstance(spec, dict):
        if "const" in spec:
            return _eval_scalar(spec["const"], context)
        if "scalar" in spec:
            return _eval_scalar(spec["scalar"], context)
        if "trace" in spec:
            return float(np.trace(_eval_element(spec["trace"], context)))
        if "tr" in spec:
            return float(np.trace(_eval_element(spec["tr"], context)))
        if "det" in spec:
            return float(np.linalg.det(_eval_element(spec["det"], context)))
        raise ValueError(f"Unsupported scalar dictionary keys: {sorted(spec.keys())}")

    array = np.asarray(spec)
    if array.shape == ():
        return float(array)

    raise TypeError(f"Unsupported scalar specification: {type(spec).__name__}")


def _eval_word(word: str, x_matrix: np.ndarray, y_matrix: np.ndarray) -> np.ndarray:
    result = _identity()
    for letter in word.strip().upper():
        if letter == "X":
            result = result @ x_matrix
        elif letter == "Y":
            result = result @ y_matrix
        elif letter == "Z":
            raise ValueError("Use _eval_element with context to evaluate words containing Z.")
        elif letter == "I":
            result = result @ _identity()
        else:
            raise ValueError(f"Unsupported word letter: {letter!r}")
    return result


def _eval_element(spec: Any, context: Dict[str, Any]) -> np.ndarray:
    x_matrix = context["x_matrix"]
    y_matrix = context["y_matrix"]

    if callable(spec):
        value = _call_with_context(
            spec,
            (x_matrix, y_matrix, context.get("base_value"), context.get("current_value")),
        )
        return _as_matrix(value, "callable element")

    if _is_scalar_like(spec):
        return float(spec) * _identity()

    if isinstance(spec, np.ndarray):
        return _as_matrix(spec, "array element")

    if isinstance(spec, str):
        text = spec.strip().upper()
        if text in {"", "I"}:
            return _identity()
        if text == "X":
            return x_matrix
        if text == "Y":
            return y_matrix
        if text == "Z":
            if "z_matrix" not in context:
                raise ValueError("Element string 'Z' requires a z_matrix in context.")
            return _as_matrix(context["z_matrix"], "z element")
        if all(letter in {"X", "Y", "I"} for letter in text):
            return _eval_word(text, x_matrix, y_matrix)
        if all(letter in {"X", "Y", "Z", "I"} for letter in text):
            result = _identity()
            for letter in text:
                if letter == "X":
                    result = result @ x_matrix
                elif letter == "Y":
                    result = result @ y_matrix
                elif letter == "Z":
                    if "z_matrix" not in context:
                        raise ValueError("Words containing Z require a z_matrix in context.")
                    result = result @ _as_matrix(context["z_matrix"], "z element")
                elif letter == "I":
                    result = result @ _identity()
            return result
        raise ValueError(f"Unsupported element string: {spec!r}")

    if isinstance(spec, dict):
        if "word" in spec:
            coeff = _eval_scalar(spec.get("coeff", 1.0), context)
            return coeff * _eval_word(str(spec["word"]), x_matrix, y_matrix)
        if "diag" in spec:
            values = [_eval_scalar(value, context) for value in spec["diag"]]
            if len(values) != MATRIX_SIZE:
                raise ValueError("Diagonal elements must have length 5.")
            return np.diag(values)
        if "scalar" in spec:
            return _eval_scalar(spec["scalar"], context) * _identity()
        if "sum" in spec:
            return sum((_eval_element(term, context) for term in spec["sum"]), np.zeros_like(_identity()))
        if "terms" in spec:
            return sum(
                (_eval_element(term, context) for term in spec["terms"]),
                np.zeros_like(_identity()),
            )
        if "product" in spec:
            result = _identity()
            for factor in spec["product"]:
                result = result @ _eval_element(factor, context)
            return result
        if "scale" in spec and "expr" in spec:
            return _eval_scalar(spec["scale"], context) * _eval_element(spec["expr"], context)
        if "commutator" in spec:
            left, right = spec["commutator"]
            left_value = _eval_element(left, context)
            right_value = _eval_element(right, context)
            return left_value @ right_value - right_value @ left_value
        if "power" in spec and "expr" in spec:
            exponent = int(spec["power"])
            if exponent < 0:
                raise ValueError("Negative powers are not supported for G elements.")
            return np.linalg.matrix_power(_eval_element(spec["expr"], context), exponent)
        raise ValueError(f"Unsupported element dictionary keys: {sorted(spec.keys())}")

    if isinstance(spec, (list, tuple)):
        if len(spec) == 2 and _is_scalar_like(spec[0]):
            return _eval_scalar(spec[0], context) * _eval_element(spec[1], context)
        return sum((_eval_element(term, context) for term in spec), np.zeros_like(_identity()))

    raise TypeError(f"Unsupported element specification: {type(spec).__name__}")


def _coefficients_from_spec(
    spec: Any,
    degree: int,
    context: Dict[str, Any],
    label: str,
) -> List[float]:
    x_matrix = context["x_matrix"]
    y_matrix = context["y_matrix"]
    base_value = context.get("base_value")
    current_value = context.get("current_value")

    if callable(spec):
        value = _call_with_context(spec, (x_matrix, y_matrix, base_value, current_value))
        return _coefficients_from_spec(value, degree, context, label)

    if isinstance(spec, dict):
        for key in ("coefficients", "coeffs", "poly"):
            if key in spec:
                return _coefficients_from_spec(spec[key], degree, context, label)
        if "constant" in spec:
            coeffs = [0.0] * (degree + 1)
            coeffs[-1] = _eval_scalar(spec["constant"], context)
            return coeffs
        raise ValueError(f"Unsupported {label} polynomial dictionary keys: {sorted(spec.keys())}")

    if not isinstance(spec, (list, tuple, np.ndarray)):
        raise TypeError(f"{label} polynomial must be a coefficient sequence or callable.")

    values = list(spec)
    if len(values) > degree + 1:
        raise ValueError(f"{label} polynomial has too many coefficients for degree {degree}.")
    if len(values) < degree + 1:
        values = [0.0] * (degree + 1 - len(values)) + values

    coeffs = [_eval_scalar(value, context) for value in values]
    if not all(math.isfinite(value) for value in coeffs):
        raise ValueError(f"{label} polynomial coefficients must be finite.")
    return coeffs


def _matrix_polynomial_terms(coefficients: Sequence[float], matrix: np.ndarray) -> List[np.ndarray]:
    degree = len(coefficients) - 1
    powers = [_identity()]
    for _ in range(degree):
        powers.append(powers[-1] @ matrix)
    return [float(coefficients[index]) * powers[degree - index] for index in range(degree + 1)]


def _matrix_norm(matrix: np.ndarray) -> float:
    if not np.all(np.isfinite(matrix)):
        return MAX_LOSS
    return float(np.linalg.norm(matrix, ord=2))


def _random_specializations(sample_count: int, seed: int) -> List[Tuple[np.ndarray, np.ndarray]]:
    rng = random.Random(seed)
    samples = []
    for _ in range(sample_count):
        x_matrix = np.array(
            [
                [rng.gauss(0.0, RANDOM_MATRIX_SCALE) for _ in range(MATRIX_SIZE)]
                for _ in range(MATRIX_SIZE)
            ],
            dtype=float,
        )
        y_matrix = np.array(
            [
                [rng.gauss(0.0, RANDOM_MATRIX_SCALE) for _ in range(MATRIX_SIZE)]
                for _ in range(MATRIX_SIZE)
            ],
            dtype=float,
        )
        samples.append((x_matrix, y_matrix))
    return samples


def _random_extended_specializations(
    sample_count: int,
    seed: int,
) -> List[Tuple[np.ndarray, np.ndarray, np.ndarray]]:
    rng = random.Random(seed)
    samples = []
    for _ in range(sample_count):
        matrices = []
        for _ in range(3):
            matrices.append(
                np.array(
                    [
                        [rng.gauss(0.0, RANDOM_MATRIX_SCALE) for _ in range(MATRIX_SIZE)]
                        for _ in range(MATRIX_SIZE)
                    ],
                    dtype=float,
                )
            )
        samples.append((matrices[0], matrices[1], matrices[2]))
    return samples


def _trim_scalar_poly(poly: Sequence[float], tolerance: float = 1e-14) -> List[float]:
    result = [float(value) for value in poly]
    while len(result) > 1 and abs(result[-1]) <= tolerance:
        result.pop()
    return result


def _scalar_poly_add(left: Sequence[float], right: Sequence[float]) -> List[float]:
    size = max(len(left), len(right))
    result = [0.0] * size
    for index in range(size):
        if index < len(left):
            result[index] += float(left[index])
        if index < len(right):
            result[index] += float(right[index])
    return _trim_scalar_poly(result)


def _scalar_poly_mul(left: Sequence[float], right: Sequence[float]) -> List[float]:
    result = [0.0] * (len(left) + len(right) - 1)
    for i, left_coeff in enumerate(left):
        for j, right_coeff in enumerate(right):
            result[i + j] += float(left_coeff) * float(right_coeff)
    return _trim_scalar_poly(result)


def _scalar_poly_compose(outer_low_to_high: Sequence[float], inner_low_to_high: Sequence[float]) -> List[float]:
    result = [0.0]
    power = [1.0]
    for coeff in outer_low_to_high:
        if coeff:
            result = _scalar_poly_add(result, [float(coeff) * value for value in power])
        power = _scalar_poly_mul(power, inner_low_to_high)
    return _trim_scalar_poly(result)


def _scalar_poly_eval_matrix(poly_low_to_high: Sequence[float], matrix: np.ndarray) -> np.ndarray:
    result = np.zeros_like(_identity())
    power = _identity()
    for coeff in poly_low_to_high:
        result = result + float(coeff) * power
        power = power @ matrix
    return result


def _matrix_coeff_poly_mul(left: Sequence[np.ndarray], right: Sequence[np.ndarray]) -> List[np.ndarray]:
    result = [np.zeros_like(_identity()) for _ in range(len(left) + len(right) - 1)]
    for i, left_coeff in enumerate(left):
        for j, right_coeff in enumerate(right):
            result[i + j] = result[i + j] + left_coeff @ right_coeff
    return result


def _as_coefficient_matrices(value: Any, context: Dict[str, Any]) -> List[np.ndarray]:
    if isinstance(value, dict):
        if "coefficients" in value:
            return _as_coefficient_matrices(value["coefficients"], context)
        if "coeffs" in value:
            return _as_coefficient_matrices(value["coeffs"], context)
        raise ValueError(f"Unsupported bivariate polynomial dictionary keys: {sorted(value.keys())}")

    if not isinstance(value, (list, tuple)):
        raise TypeError("Bivariate polynomial coefficients must be returned as a list or tuple.")

    return [_as_matrix(_eval_element(coefficient, context), "bivariate coefficient") for coefficient in value]


def _extended_polynomial_data(poly_spec: Any, context: Dict[str, Any]) -> Tuple[np.ndarray | None, List[np.ndarray]]:
    x_matrix = context["x_matrix"]
    y_matrix = context["y_matrix"]
    z_matrix = context["z_matrix"]
    base_value = context.get("base_value")
    current_value = context.get("current_value")

    if callable(poly_spec):
        value = _call_with_context(poly_spec, (x_matrix, y_matrix, z_matrix, base_value, current_value))
    else:
        value = poly_spec

    explicit_value = None
    if isinstance(value, dict):
        if "value" in value:
            explicit_value = _as_matrix(_eval_element(value["value"], context), "bivariate value")
        for key in ("coefficients", "coeffs"):
            if key in value:
                return explicit_value, _as_coefficient_matrices(value[key], context)
        raise ValueError(f"Unsupported bivariate polynomial dictionary keys: {sorted(value.keys())}")

    return explicit_value, _as_coefficient_matrices(value, context)


def eval_f_of_elem(
    s_coefficients: Any,
    element: Any,
    sample_count: int = STAGE2_SAMPLES,
    seed: int = 12345,
    samples: Iterable[Tuple[np.ndarray, np.ndarray]] | None = None,
    base_element: Any | None = None,
) -> float:
    """Evaluate the normalized sampled L2 error for s(element).

    For s(t)=a_0 t^5 + ... + a_5 and an element r in G, this computes

        sqrt(mean_{A,B} ( ||s(r)(A,B)|| /
             (||a_0 r^5(A,B)|| + ... + ||a_5 I||) )^2).

    Coefficients may be constants or callables evaluated at each specialization.
    """
    specializations = list(samples) if samples is not None else _random_specializations(sample_count, seed)
    if not specializations:
        raise ValueError("eval_f_of_elem requires at least one specialization.")

    squared_ratios = []
    for x_matrix, y_matrix in specializations:
        context: Dict[str, Any] = {"x_matrix": x_matrix, "y_matrix": y_matrix}
        if base_element is not None:
            context["base_value"] = _eval_element(base_element, context)

        current_value = _eval_element(element, context)
        context["current_value"] = current_value
        coefficients = _coefficients_from_spec(s_coefficients, F_DEGREE, context, "f")
        terms = _matrix_polynomial_terms(coefficients, current_value)
        numerator = _matrix_norm(sum(terms, np.zeros_like(_identity())))
        denominator = sum(_matrix_norm(term) for term in terms)

        if denominator <= DENOMINATOR_EPS:
            ratio = 0.0 if numerator <= DENOMINATOR_EPS else MAX_LOSS
        else:
            ratio = numerator / denominator
        if not math.isfinite(ratio):
            ratio = MAX_LOSS
        squared_ratios.append(min(ratio, MAX_LOSS) ** 2)

    return float(math.sqrt(sum(squared_ratios) / len(squared_ratios)))


def _monic_quintic_discriminant_terms(f_coefficients: Sequence[float]) -> List[float]:
    """Evaluate all 59 terms of the monic quintic discriminant."""
    if len(f_coefficients) != F_DEGREE + 1:
        raise ValueError("f must have exactly 6 high-to-low coefficients.")

    leading = float(f_coefficients[0])
    if abs(leading) <= DENOMINATOR_EPS:
        raise ValueError("f must have nonzero leading coefficient for discriminant normalization.")

    monic_tail = [float(value) / leading for value in f_coefficients[1:]]
    term_values = []
    for integer_coefficient, exponents in MONIC_QUINTIC_DISCRIMINANT_TERMS:
        value = float(integer_coefficient)
        try:
            for base, exponent in zip(monic_tail, exponents):
                if exponent:
                    value *= base**exponent
        except OverflowError:
            value = MAX_LOSS
        if not math.isfinite(value):
            value = math.copysign(MAX_LOSS, value)
        term_values.append(value)
    return term_values


def sep_measure(
    f_coefficients: Any,
    sample_count: int = STAGE2_SAMPLES,
    seed: int = 24680,
    samples: Iterable[Tuple[np.ndarray, np.ndarray]] | None = None,
) -> float:
    """Evaluate the normalized discriminant separation measure for f(t).

    For each specialization, the numerator is the absolute monic quintic
    discriminant. The denominator is the sum of the absolute values of the 59
    monic discriminant terms at that same specialization.
    """
    specializations = list(samples) if samples is not None else _random_specializations(sample_count, seed)
    if not specializations:
        raise ValueError("sep_measure requires at least one specialization.")

    squared_ratios = []
    for x_matrix, y_matrix in specializations:
        context: Dict[str, Any] = {"x_matrix": x_matrix, "y_matrix": y_matrix}
        coefficients = _coefficients_from_spec(f_coefficients, F_DEGREE, context, "f")
        terms = _monic_quintic_discriminant_terms(coefficients)
        numerator = abs(sum(terms))
        denominator = sum(abs(term) for term in terms)

        if denominator <= DENOMINATOR_EPS:
            ratio = 0.0 if numerator <= DENOMINATOR_EPS else MAX_LOSS
        else:
            ratio = numerator / denominator
        if not math.isfinite(ratio):
            ratio = MAX_LOSS
        squared_ratios.append(min(ratio, MAX_LOSS) ** 2)

    return float(math.sqrt(sum(squared_ratios) / len(squared_ratios)))


def extended_eval_f_of_elem(
    r_coefficients: Any,
    element: Any,
    sample_count: int = STAGE2_SAMPLES,
    seed: int = 13579,
    samples: Iterable[Tuple[np.ndarray, np.ndarray, np.ndarray]] | None = None,
) -> float:
    """Evaluate a normalized bivariate relation r(element, z).

    The input r_coefficients may be a callable returning either:
    - a list of coefficient matrices for powers of t, low-to-high, or
    - {"value": matrix, "coefficients": coefficient_matrices}.

    The denominator is the sum of matrix 2-norms of the coefficient matrices
    after X=A, Y=B, and z=C have been specialized.
    """
    specializations = (
        list(samples)
        if samples is not None
        else _random_extended_specializations(sample_count, seed)
    )
    if not specializations:
        raise ValueError("extended_eval_f_of_elem requires at least one specialization.")

    squared_ratios = []
    for x_matrix, y_matrix, z_matrix in specializations:
        context: Dict[str, Any] = {
            "x_matrix": x_matrix,
            "y_matrix": y_matrix,
            "z_matrix": z_matrix,
        }
        element_value = _eval_element(element, context)
        context["base_value"] = element_value
        context["current_value"] = element_value

        explicit_value, coefficient_matrices = _extended_polynomial_data(r_coefficients, context)
        if not coefficient_matrices:
            raise ValueError("Bivariate relation must have at least one coefficient.")

        if explicit_value is None:
            powers = [_identity()]
            for _ in range(len(coefficient_matrices) - 1):
                powers.append(powers[-1] @ element_value)
            explicit_value = sum(
                (
                    coefficient_matrices[index] @ powers[index]
                    for index in range(len(coefficient_matrices))
                ),
                np.zeros_like(_identity()),
            )

        numerator = _matrix_norm(explicit_value)
        denominator = sum(_matrix_norm(coefficient) for coefficient in coefficient_matrices)
        if denominator <= DENOMINATOR_EPS:
            ratio = 0.0 if numerator <= DENOMINATOR_EPS else MAX_LOSS
        else:
            ratio = numerator / denominator
        if not math.isfinite(ratio):
            ratio = MAX_LOSS
        squared_ratios.append(min(ratio, MAX_LOSS) ** 2)

    return float(math.sqrt(sum(squared_ratios) / len(squared_ratios)))


def _orbit_zeroes_relation(f: Any, h: Any) -> Callable:
    """Return data for product_i (z - h^i(t)) - f(z)."""

    def relation(
        x_matrix: np.ndarray,
        y_matrix: np.ndarray,
        z_matrix: np.ndarray,
        base_value: np.ndarray | None = None,
        current_value: np.ndarray | None = None,
    ) -> Dict[str, Any]:
        context: Dict[str, Any] = {
            "x_matrix": x_matrix,
            "y_matrix": y_matrix,
            "z_matrix": z_matrix,
            "base_value": base_value,
            "current_value": current_value,
        }
        if base_value is None:
            raise ValueError("Orbit relation requires the evaluated g as base_value.")

        f_coefficients = _coefficients_from_spec(f, F_DEGREE, context, "f")
        h_coefficients = _coefficients_from_spec(h, H_DEGREE, context, "h")
        h_low = [float(value) for value in reversed(h_coefficients)]

        h_iterates = []
        scalar_iterate = [0.0, 1.0]
        for _ in range(FIRST_PART_ITERATES):
            h_iterates.append(scalar_iterate)
            scalar_iterate = _scalar_poly_compose(h_low, scalar_iterate)

        product_coefficients = [_identity()]
        product_value = _identity()
        for scalar_poly in h_iterates:
            h_of_g = _scalar_poly_eval_matrix(scalar_poly, base_value)
            product_value = product_value @ (z_matrix - h_of_g)

            factor_coefficients = [z_matrix - scalar_poly[0] * _identity()]
            for coeff in scalar_poly[1:]:
                factor_coefficients.append(-float(coeff) * _identity())
            product_coefficients = _matrix_coeff_poly_mul(product_coefficients, factor_coefficients)

        f_of_z = sum(_matrix_polynomial_terms(f_coefficients, z_matrix), np.zeros_like(_identity()))
        product_value = product_value - f_of_z
        product_coefficients[0] = product_coefficients[0] - f_of_z
        return {"value": product_value, "coefficients": product_coefficients}

    return relation


def _lambda_sep_value() -> float:
    raw_value = os.environ.get("LAMBDA_SEP")
    if raw_value is None:
        return DEFAULT_LAMBDA_SEP
    try:
        value = float(raw_value)
    except ValueError:
        return DEFAULT_LAMBDA_SEP
    if not math.isfinite(value):
        return DEFAULT_LAMBDA_SEP
    return max(0.0, value)


def _lambda_orbit_zeroes_f_value() -> float:
    raw_value = os.environ.get("LAMBDA_ORBIT_ZEROES_F")
    if raw_value is None:
        return DEFAULT_LAMBDA_ORBIT_ZEROES_F
    try:
        value = float(raw_value)
    except ValueError:
        return DEFAULT_LAMBDA_ORBIT_ZEROES_F
    if not math.isfinite(value):
        return DEFAULT_LAMBDA_ORBIT_ZEROES_F
    return max(0.0, value)


